class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def solve(root):
    if not root:
        return 0
    def get_depth(node, get_left):
        d = 0
        while node:
            node = node.left if get_left else node.right
            d += 1
        return d

    left_d = get_depth(root, True)
    right_d = get_depth(root, False)

    if left_d == right_d:
        return (1 << left_d) - 1
    return 1 + solve(root.left) + solve(root.right)

